const text = ($input.item.json.message?.text || '').trim();

// Yesterday prefix: y:300 lunch
const isYesterday = /^y:/i.test(text);
let cleanText = isYesterday ? text.replace(/^y:/i, '').trim() : text;

// Business prefix: b:500 vendor
const forceBusiness = /^b:/i.test(cleanText);
cleanText = forceBusiness ? cleanText.replace(/^b:/i, '').trim() : cleanText;

// Date
const now = new Date();
const yest = new Date(now);
yest.setDate(yest.getDate() - 1);
const date = isYesterday ? yest.toISOString().split('T')[0] : now.toISOString().split('T')[0];

// Payment method (first word)
const methodMap = {cash:'Cash',upi:'UPI',card:'Card',neft:'NEFT',rtgs:'RTGS',cheque:'Cheque',gpay:'UPI',paytm:'UPI',phonepe:'UPI',netbanking:'NEFT'};
const words = cleanText.split(/\s+/);
let paymentMethod = 'UPI';
let remaining = cleanText;
if (methodMap[words[0].toLowerCase()]) {
  paymentMethod = methodMap[words[0].toLowerCase()];
  remaining = words.slice(1).join(' ');
}

// Strip currency symbols (₹, $, €, £, ¥)
remaining = remaining.replace(/^[\u20B9$€£¥]/,'').trim();

// Amount: supports 5k = 5000, commas 1,500, decimals
const kMatch = remaining.match(/(\d[\d,]*(?:\.\d+)?)\s*k\b/i);
const numMatch = remaining.match(/(\d[\d,]*(?:\.\d{1,2})?)/);
let amount = 0, amountStr = '';
if (kMatch) {
  amount = parseFloat(kMatch[1].replace(/,/g,'')) * 1000;
  amountStr = kMatch[0];
} else if (numMatch) {
  amount = parseFloat(numMatch[1].replace(/,/g,''));
  amountStr = numMatch[0];
}

// Merchant aliases (common shorthand)
const aliases = {
  sbux:'Starbucks', starbux:'Starbucks', bucks:'Starbucks',
  mcds:'McDonalds', mcd:'McDonalds',
  swgy:'Swiggy', zmto:'Zomato',
  amzn:'Amazon', fkrt:'Flipkart', flpkrt:'Flipkart',
  dom:'Dominos', dominos:'Dominos',
  bk:'Burger King', kfc:'KFC',
  ola:'Ola Cab', uber:'Uber'
};

const afterAmount = remaining.replace(amountStr, '').trim();
const afterWords = afterAmount.split(/\s+/).filter(Boolean);
const rawMerchant = afterWords[0] || '';
const merchant = aliases[rawMerchant.toLowerCase()] ||
  (rawMerchant ? rawMerchant.charAt(0).toUpperCase() + rawMerchant.slice(1) : 'Unknown');
const notes = afterWords.slice(1).join(' ') || '';

return [{ json: {
  amount, date, merchant, paymentMethod,
  userNote: notes,
  forceBusiness, isYesterday,
  rawText: text, driveLink: '', ocrSuccess: true
} }];

const input = $input.item.json;
const text = (input.rawText + ' ' + input.merchant).toLowerCase();
const userNote = (input.userNote || '').toLowerCase();
const forceBusiness = input.forceBusiness;

const rules = [
  { category: 'Food & Drink',        type: 'Personal', keywords: ['zomato','swiggy','starbucks','cafe','restaurant','biryani','pizza','food','eat','dominos','mcdonald','kfc','burger','dine','lunch','dinner','breakfast','coffee','chai','tea'] },
  { category: 'Transport',           type: 'Personal', keywords: ['uber','ola','rapido','petrol','fuel','toll','parking','auto','cab','rickshaw','metro','bus','train fare','ticket'] },
  { category: 'Shopping',            type: 'Personal', keywords: ['amazon','flipkart','myntra','mall','store','shop','meesho','retail','ajio','snapdeal','clothes','apparel'] },
  { category: 'Bills & Utilities',   type: 'Personal', keywords: ['electricity','water','broadband','jio','airtel','bsnl','recharge','bill','internet','wifi','gas cylinder','piped gas','rent','landlord'] },
  { category: 'Medical',             type: 'Personal', keywords: ['pharmacy','hospital','doctor','clinic','medicine','apollo','medplus','health','dental','lab test','1mg','netmeds'] },
  { category: 'Business - Software', type: 'Business', keywords: ['aws','google cloud','notion','slack','zoom','adobe','subscription','saas','github','figma','canva','digitalocean','heroku'] },
  { category: 'Business - Travel',   type: 'Business', keywords: ['flight','hotel','train ticket','business travel','airport','business cab'] },
  { category: 'Business - Meals',    type: 'Business', keywords: ['client lunch','vendor meeting','team lunch','business meal','office lunch','client dinner'] },
  { category: 'Business - Supplies', type: 'Business', keywords: ['office supplies','stationery','equipment','printer','laptop','monitor'] },
  { category: 'Vendor Payment',      type: 'Business', keywords: ['vendor','supplier','contractor','invoice','advance payment'] },
  { category: 'Cash',                type: 'Personal', keywords: ['atm','cash withdrawal','cash advance'] },
];

let category = 'Other';
let type = 'Personal';
for (const rule of rules) {
  if (rule.keywords.some(kw => text.includes(kw) || userNote.includes(kw))) {
    category = rule.category;
    type = rule.type;
    break;
  }
}
if (forceBusiness) type = 'Business';

return [{ json: { ...input, category, type } }];
